// CONFIG
const YEARLY_VARIABLE = 120000;
const WORKING_DAYS = 24;

// CALCULATIONS
const monthlyVariable = YEARLY_VARIABLE / 12;   // 10000
const dailyBucket = monthlyVariable * 0.5;      // 5000
const dailyCap = dailyBucket / WORKING_DAYS;    // 208.33

// INPUTS
const completedTasks = $input.all(0).map(i => i.json); // Node 2
const creditedRows = $input.all(1).map(i => i.json);   // Node 3

// Build credited map
const creditedMap = {};
for (const row of creditedRows) {
  creditedMap[row.user_id] = Number(row.credited_today || 0);
}

const output = [];

for (const task of completedTasks) {
  const userId = task.user_id;
  const taskId = task.task_id;

  const alreadyCredited = creditedMap[userId] || 0;
  const remaining = dailyCap - alreadyCredited;

  if (remaining <= 0) continue;

  output.push({
    json: {
      user_id: userId,
      task_id: taskId,
      points: Number(remaining.toFixed(2)),
      remark: 'Daily variable task reward'
    }
  });
}

return output;

const DAILY_CAP = 208.33;
const TASK_PERCENT = 0.20;
const DAILY_TASK_MAX = DAILY_CAP * TASK_PERCENT; // 41.66

const items = $input.all();

const assignedMap = {};
const completedMap = {};

for (const item of items) {
  const data = item.json;

  if (data.total_tasks_today !== undefined) {
    assignedMap[data.user_id] = Number(data.total_tasks_today);
  }

  if (data.completed_tasks_today !== undefined) {
    completedMap[data.user_id] = Number(data.completed_tasks_today);
  }
}

const output = [];

for (const userId in assignedMap) {
  const total = assignedMap[userId];
  const done = completedMap[userId] || 0;

  if (!total || total <= 0 || done <= 0) continue;

  const ratio = done / total;
  const points = Math.min(
    DAILY_TASK_MAX,
    Number((ratio * DAILY_TASK_MAX).toFixed(2))
  );

  if (points <= 0) continue;

  output.push({
    json: {
      user_id: Number(userId),
      points,
      remark: `Daily task completion: ${done}/${total}`
    }
  });
}

return output;

const DAILY_TODO_POOL = 20.83; // 10% of daily pool (≈ 208.33 * 10%)

const output = [];

for (const item of $input.all()) {
  const user_id = item.json.user_id;
  const total = Number(item.json.total_todos_today || 0);
  const completed = Number(item.json.completed_todos_today || 0);

  if (total === 0) continue;

  const ratio = completed / total;
  let points = ratio * DAILY_TODO_POOL;

  // safety cap
  if (points > DAILY_TODO_POOL) {
    points = DAILY_TODO_POOL;
  }

  points = Number(points.toFixed(2));

  if (points <= 0) continue;

  output.push({
    json: {
      user_id,
      points,
      remark: `Daily todo completion: ${completed}/${total}`
    }
  });
}

return output;

const map = {};

for (const item of $input.all()) {
  const data = item.json;
  const userId = data.user_id;

  if (!map[userId]) {
    map[userId] = {
      user_id: userId,
      total_todos_today: 0,
      completed_todos_today: 0
    };
  }

  if (typeof data.total_todos_today === 'number') {
    map[userId].total_todos_today = data.total_todos_today;
  }

  if (typeof data.completed_todos_today === 'number') {
    map[userId].completed_todos_today = data.completed_todos_today;
  }
}

return Object.values(map).map(v => ({ json: v }));
